import os
from PIL import Image

# Define directory to search and PDF saving path
directory = "/home/user/"
output_pdf_path = "/home/user/Desktop/receipt.pdf"

# Function to find the receipt image dynamically
def find_receipt_image(directory):
    extensions = [".jpg", ".jpeg", ".png", ".tiff", ".bmp"]  # Common image formats
    for file in os.listdir(directory):
        if any(file.endswith(ext) for ext in extensions) and "receipt" in file.lower():
            return os.path.join(directory, file)
    return None

# Attempt to locate and convert the image
receipt_image_path = find_receipt_image(directory)
if receipt_image_path:
    try:
        with Image.open(receipt_image_path) as img:
            img = img.convert("RGB")  # Convert to PDF-compatible format
            img.save(output_pdf_path, "PDF")
            print(f"Successfully saved the receipt as:\n{output_pdf_path}")
    except Exception as e:
        print(f"An error occurred while processing the image: {e}")
else:
    print("Receipt image not found. Please ensure it is in the /home/user directory with a name containing 'receipt'.")
