import os
from PIL import Image

# Define directory to search and PDF saving path
directory = "/home/user/"
output_pdf_path = "/home/user/Desktop/receipt.pdf"

# Function to find the first image in the directory
def find_any_image(directory):
    extensions = [".jpg", ".jpeg", ".png", ".tiff", ".bmp"]  # Common image formats
    for file in os.listdir(directory):
        if any(file.endswith(ext) for ext in extensions):
            return os.path.join(directory, file)
    return None

# Attempt to locate and convert the image
image_path = find_any_image(directory)
if image_path:
    try:
        with Image.open(image_path) as img:
            img = img.convert("RGB")  # Convert to PDF-compatible format
            img.save(output_pdf_path, "PDF")
            print(f"Successfully saved the image as a PDF:\n{output_pdf_path}")
    except Exception as e:
        print(f"An error occurred while processing the image: {e}")
else:
    print("No image found in /home/user. Please add an image to convert.")
